class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        int len1 = s1.length(), len2 = s2.length();
        int[] nextIndex = new int[len2];
        int[] count = new int[len2];
        int j = 0, cnt = 0;
        for (int i = 0; i < len1; i++) {
            if (s1.charAt(i) == s2.charAt(j)) {
                j++;
                if (j == len2) {
                    j = 0;
                    cnt++;
                }
            }
            nextIndex[i] = j;
            count[i] = cnt;
        }

        int totalCnt = 0;
        j = 0;
        for (int i = 0; i < n1; i++) {
            totalCnt += count[j];
            j = nextIndex[j];
        }
        return totalCnt / n2;
    }
}
